internal final class ETGDeliveryReportUIBuilder extends SrsReportDataContractUIBuilder
{
    DialogField dlgFromDate, dlgToDate, dlgCommodity, dlgSubCommodity, dlgSalesAgreementNumber, dlgAgreementDate;
        ETGDeliveryScheduleReportContract contract;

}

Method.Source:
public void build()
{
    contract = this.dataContractObject();

    this.addDialogField(methodStr(ETGDeliveryScheduleReportContract, parmFromDate), contract);
    this.addDialogField(methodStr(ETGDeliveryScheduleReportContract, parmToDate), contract);
    this.addDialogField(methodStr(ETGDeliveryScheduleReportContract, parmETGCommodity), contract);
    this.addDialogField(methodStr(ETGDeliveryScheduleReportContract, parmETGSubCommodity), contract);
}

public void postBuild()
{
    super();

    dlgCommodity = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGDeliveryScheduleReportContract, parmETGCommodity));
    dlgSubCommodity = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGDeliveryScheduleReportContract, parmETGSubCommodity));

    dlgCommodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGDeliveryReportUIBuilder, lookupCommodity), this);
    dlgSubCommodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGDeliveryReportUIBuilder, lookupETGSubCommodity), this);

}

